// ===== NESTING-AWARE SLIDE-FIT LAYOUT =====
function autoLayout(data) {
  const nds = (data.nodes||[]).filter(n=>ALL[n.type]);
  const grps = data.groups||[];
  const edgeList = data.edges||[];
  const grpMap = {}; grps.forEach(g=>{ grpMap[g.id]=g; });
  const nodeW=72, nodeH=74, gPadX=20, gPadY=16, gTop=32, gGap=20, nestPad=12;

  // Separate node children and group children for each group
  const grpIds = new Set(grps.map(g=>g.id));
  const childGroups = {}; // gid -> [child group ids]
  const childNodes = {};  // gid -> [child node objects]
  const parentOf = {};    // gid -> parent gid
  grps.forEach(g=>{
    const cg = [], cn = [];
    (g.children||[]).forEach(cid=>{
      if(grpIds.has(cid)){ cg.push(cid); parentOf[cid]=g.id; }
      else { const nd = nds.find(n=>n.id===cid); if(nd) cn.push(nd); }
    });
    childGroups[g.id]=cg;
    childNodes[g.id]=cn;
  });

  // Find root groups (no parent)
  const roots = grps.filter(g=>!parentOf[g.id]);

  // Compute depth for rendering order
  const depth = {};
  function setDepth(gid, d) { depth[gid]=d; (childGroups[gid]||[]).forEach(cid=>setDepth(cid,d+1)); }
  roots.forEach(g=>setDepth(g.id, 0));

  // Size groups bottom-up (leaves first)
  const gSize = {}; // gid -> {w, h, cols, rows}
  function sizeGroup(gid) {
    const cgs = childGroups[gid]||[];
    const cns = childNodes[gid]||[];
    // Size child groups first
    cgs.forEach(cid=>sizeGroup(cid));

    // Child groups laid out horizontally
    let cgW=0, cgH=0;
    cgs.forEach(cid=>{ cgW+=gSize[cid].w+gGap; cgH=Math.max(cgH, gSize[cid].h); });
    if(cgs.length) cgW-=gGap; // remove trailing gap

    // Direct nodes in a grid row below (or beside) child groups
    const nCols = cns.length<=3?cns.length:Math.min(4,cns.length);
    const nRows = Math.ceil((cns.length||0)/(nCols||1));
    const nodesW = nCols*nodeW;
    const nodesH = nRows*nodeH;

    // Total inner content
    const innerW = Math.max(cgW, nodesW);
    const innerH = (cgH>0&&nodesH>0) ? cgH+gGap+nodesH : cgH+nodesH;

    gSize[gid] = {
      w: Math.max(160, innerW + gPadX*2),
      h: Math.max(100, innerH + gTop + gPadY*2),
      cgW, cgH, nCols, nRows, nodesW, nodesH
    };
  }
  grps.forEach(g=>{ if(!parentOf[g.id]) sizeGroup(g.id); });

  // Position groups top-down
  const gPos = {}; // gid -> {x, y}
  const nPos = {}; // nid -> {x, y}

  function positionGroup(gid, ox, oy) {
    gPos[gid] = {x:ox, y:oy};
    const s = gSize[gid];
    const cgs = childGroups[gid]||[];
    const cns = childNodes[gid]||[];
    const contentX = ox + gPadX;
    const contentY = oy + gTop + gPadY;

    // Position child groups horizontally
    let cx = contentX + Math.max(0, (s.w-gPadX*2-s.cgW)/2); // center child groups
    cgs.forEach(cid=>{
      const cs = gSize[cid];
      positionGroup(cid, cx, contentY);
      cx += cs.w + gGap;
    });

    // Position direct nodes below child groups (or at top if no child groups)
    const nodeStartY = s.cgH>0 ? contentY + s.cgH + gGap : contentY;
    const nodeStartX = contentX + Math.max(0, (s.w-gPadX*2-s.nodesW)/2); // center nodes
    cns.forEach((n,i)=>{
      const col = i % (s.nCols||1);
      const row = Math.floor(i / (s.nCols||1));
      nPos[n.id] = {
        x: nodeStartX + nodeW/2 + col*nodeW,
        y: nodeStartY + nodeH/2 + row*nodeH
      };
    });
  }

  // Flow-sort roots using edge topology between root groups
  function rootOf(nid) {
    // Find which root group this node belongs to
    for (const g of grps) {
      if ((g.children||[]).includes(nid)) {
        let gid = g.id;
        while(parentOf[gid]) gid=parentOf[gid];
        return gid;
      }
    }
    return null;
  }
  const rootAdj={}; const rootInDeg={};
  roots.forEach(g=>{rootAdj[g.id]=new Set();rootInDeg[g.id]=0;});
  edgeList.forEach(e=>{
    const rf=rootOf(e.from), rt=rootOf(e.to);
    if(rf&&rt&&rf!==rt&&rootAdj[rf]&&!rootAdj[rf].has(rt)){
      rootAdj[rf].add(rt); rootInDeg[rt]=(rootInDeg[rt]||0)+1;
    }
  });
  // Topo sort
  const sorted=[]; const vis=new Set(); const q=roots.filter(g=>!rootInDeg[g.id]).map(g=>g.id);
  while(q.length){ const nx=[]; q.forEach(gid=>{sorted.push(gid);vis.add(gid);rootAdj[gid]?.forEach(dep=>{rootInDeg[dep]--;if(!rootInDeg[dep]&&!vis.has(dep))nx.push(dep);});}); q.length=0;q.push(...nx); }
  roots.forEach(g=>{if(!vis.has(g.id))sorted.push(g.id);});

  // Place root groups left-to-right
  let rx=30;
  const maxH = Math.max(100,...sorted.map(gid=>gSize[gid]?.h||0));
  sorted.forEach(gid=>{
    const s=gSize[gid];
    const ry = Math.max(30, (maxH-s.h)/2+30); // vertically center
    positionGroup(gid, rx, ry);
    rx += s.w + gGap*1.5;
  });

  // Ungrouped nodes
  const allGroupedNodes = new Set();
  function collectNodes(gid){ (childNodes[gid]||[]).forEach(n=>allGroupedNodes.add(n.id)); (childGroups[gid]||[]).forEach(cid=>collectNodes(cid)); }
  grps.forEach(g=>collectNodes(g.id));
  const ung = nds.filter(n=>!allGroupedNodes.has(n.id));
  if(ung.length){
    const uy = 40;
    ung.forEach((n,i)=>{ nPos[n.id]={x:rx+nodeW/2+(i%2)*nodeW, y:uy+nodeH/2+Math.floor(i/2)*nodeH}; });
  }

  // Sort groups by depth for rendering (outer first)
  const sortedGrps = [...grps].sort((a,b)=>(depth[a.id]||0)-(depth[b.id]||0));

  return {
    title:data.title,
    nodes:nds.map(n=>({id:n.id,type:n.type,label:n.label,x:nPos[n.id]?.x??300,y:nPos[n.id]?.y??300})),
    groups:sortedGrps.filter(g=>GT[g.type]&&gPos[g.id]).map(g=>{
      const s=gSize[g.id]; const p=gPos[g.id]; const tpl=GT[g.type]||GT.rg;
      const d = depth[g.id]||0;
      return {id:g.id,type:g.type,label:g.label,x:p.x,y:p.y,w:s.w,h:s.h,
        color:tpl.color,border:tpl.border,dash:!!tpl.dash,depth:d};
    }),
    edges:edgeList.map((e,i)=>({id:`e${i}`,from:e.from,to:e.to,label:e.label||"",style:e.style||"solid"})),
  };
}

// ===== EDGE ROUTING (orthogonal-ish with bezier) =====
function edgePath(a,b) {
  const dx=b.x-a.x,dy=b.y-a.y,d=Math.sqrt(dx*dx+dy*dy);
  if(d<1) return `M${a.x},${a.y}`;
  const absDx=Math.abs(dx),absDy=Math.abs(dy);
  const curve=Math.min(50,d*0.25);
  const nx=dx/d,ny=dy/d;
  const oA=a.r||30, oB=b.r||30;
  const sx=a.x+nx*oA,sy=a.y+ny*oA,ex=b.x-nx*oB,ey=b.y-ny*oB;
  // Prefer horizontal/vertical routing
  if(absDx>absDy*1.5){
    // Mostly horizontal
    const midX=(sx+ex)/2;
    return `M${sx},${sy} C${midX},${sy} ${midX},${ey} ${ex},${ey}`;
  } else if(absDy>absDx*1.5){
    // Mostly vertical
    const midY=(sy+ey)/2;
    return `M${sx},${sy} C${sx},${midY} ${ex},${midY} ${ex},${ey}`;
  }
  // Diagonal - slight curve
  const mx=(sx+ex)/2-ny*curve*0.4,my=(sy+ey)/2+nx*curve*0.4;
  return `M${sx},${sy} Q${mx},${my} ${ex},${ey}`;
}

const TH={
  dark:{bg:"#080c18",srf:"#0c1225",text:"#e2e8f0",ts:"#94a3b8",tm:"#64748b",tf:"#475569",bdr:"#1e293b",sel:"#3b82f6",hbg:"#0c1225ee",nBg:"#111827",nSt:"#1e293b"},
  light:{bg:"#f8fafc",srf:"#ffffff",text:"#0f172a",ts:"#475569",tm:"#94a3b8",tf:"#cbd5e1",bdr:"#e2e8f0",sel:"#3b82f6",hbg:"#ffffffee",nBg:"#ffffff",nSt:"#e2e8f0"},
};

export default function App(){
  const [nodes,setNodes]=useState([]);const [groups,setGroups]=useState([]);const [edges,setEdges]=useState([]);const [sel,setSel]=useState(null);const [connectFrom,setConnectFrom]=useState(null);const [drag,setDrag]=useState(null);const [rsz,setRsz]=useState(null);const [pan,setPan]=useState({x:0,y:0});const [panSt,setPanSt]=useState(null);const [zoom,setZoom]=useState(1);const [edgeLbl,setEdgeLbl]=useState("");const [edgeStyle,setEdgeStyle]=useState("solid");const [title,setTitle]=useState("Azure Deployment Diagram");const [grid,setGrid]=useState(true);const [input,setInput]=useState("");const [activeEx,setActiveEx]=useState(null);const [theme,setTheme]=useState("dark");const [editMode,setEditMode]=useState(false);const [showPalette,setShowPalette]=useState(false);const [openCat,setOpenCat]=useState(null);const [drawerOpen,setDrawerOpen]=useState(false);const [isMobile]=useState(typeof window!=="undefined"&&window.innerWidth<768);const [hasData,setHasData]=useState(false);
  const svgRef=useRef(null);const mainRef=useRef(null);const nid=useRef(100);const gid=useRef(100);const T=TH[theme];

  // Auto zoom-to-fit
  const zoomToFit = useCallback((nds, gps) => {
    if (!svgRef.current) return;
    const r = svgRef.current.getBoundingClientRect();
    const vw = r.width, vh = r.height;
    // Find bounding box of all content
    let minX=Infinity,minY=Infinity,maxX=-Infinity,maxY=-Infinity;
    nds.forEach(n => { minX=Math.min(minX,n.x-40);minY=Math.min(minY,n.y-40);maxX=Math.max(maxX,n.x+40);maxY=Math.max(maxY,n.y+60); });
    gps.forEach(g => { minX=Math.min(minX,g.x);minY=Math.min(minY,g.y);maxX=Math.max(maxX,g.x+g.w);maxY=Math.max(maxY,g.y+g.h); });
    if(minX===Infinity) return;
    const cw=maxX-minX+80, ch=maxY-minY+80;
    const z=Math.min(vw/cw, vh/ch, 1.5);
    const px=(vw-cw*z)/2-minX*z+40;
    const py=(vh-ch*z)/2-minY*z+40;
    setZoom(z); setPan({x:px,y:py});
  }, []);

  const [loading,setLoading]=useState(false);
  const [genError,setGenError]=useState(null);

  const SERVICE_TYPES = Object.keys(ALL).join(", ");
  const generate = async () => {
    if (!input.trim()) return;
    setLoading(true); setGenError(null);
    try {
      const prompt = `Return ONLY a JSON object for an Azure deployment diagram. No markdown, no backticks, no explanation.

Schema: {"title":"str","groups":[{"id":"g1","type":"rg","label":"str","children":["n1","g2"]}],"nodes":[{"id":"n1","type":"vm","label":"str"}],"edges":[{"from":"n1","to":"n2","label":"","style":"solid"}]}

Node types: ${SERVICE_TYPES}
Group types: rg, vnet_grp, subnet_grp, aks_grp, region, onprem, custom
Groups can nest: children[] can contain node IDs and group IDs.
Use dashed edges for monitoring, solid for data. 8-20 nodes, 2-6 groups.

Architecture: ${input.trim()}`;

      const resp = await fetch("/api/anthropic", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 4096,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await resp.json();
      if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));
      const text = (data.content||[]).filter(c=>c.type==="text").map(c=>c.text).join("");
      const si = text.indexOf("{"), ei = text.lastIndexOf("}");
      if (si === -1) throw new Error("No JSON in response");
      let parsed;
      try { parsed = JSON.parse(text.slice(si, ei+1)); }
      catch(e) { parsed = JSON.parse(text.slice(si, ei+1).replace(/,\s*([}\]])/g, "$1")); }
      parsed.nodes = (parsed.nodes||[]).filter(n=>ALL[n.type]);
      parsed.groups = (parsed.groups||[]).filter(g=>GT[g.type]);
      const nIds = new Set(parsed.nodes.map(n=>n.id));
      parsed.edges = (parsed.edges||[]).filter(e=>nIds.has(e.from)&&nIds.has(e.to));
      const r = autoLayout(parsed);
      setTitle(r.title||"Azure Diagram"); setNodes(r.nodes); setGroups(r.groups); setEdges(r.edges);
      setSel(null); setHasData(true);
      if(isMobile) setDrawerOpen(false);
      setTimeout(()=>zoomToFit(r.nodes,r.groups),100);
    } catch(err) { setGenError(err.message); }
    finally { setLoading(false); }
  };

  const loadDemo=(k)=>{const d=DEMOS[k];if(!d)return;const r=autoLayout(d);setTitle(r.title);setNodes(r.nodes);setGroups(r.groups);setEdges(r.edges);setSel(null);setHasData(true);if(isMobile)setDrawerOpen(false);setTimeout(()=>zoomToFit(r.nodes,r.groups),100);};
  const loadJson=()=>{try{const si=input.indexOf("{"),ei=input.lastIndexOf("}");if(si===-1)throw new Error("No JSON");const p=JSON.parse(input.slice(si,ei+1));p.nodes=(p.nodes||[]).filter(n=>ALL[n.type]);p.groups=(p.groups||[]).filter(g=>GT[g.type]);const ids=new Set(p.nodes.map(n=>n.id));p.edges=(p.edges||[]).filter(e=>ids.has(e.from)&&ids.has(e.to));const r=autoLayout(p);setTitle(r.title||"Custom");setNodes(r.nodes);setGroups(r.groups);setEdges(r.edges);setSel(null);setHasData(true);if(isMobile)setDrawerOpen(false);setTimeout(()=>zoomToFit(r.nodes,r.groups),100);}catch(e){alert("Invalid JSON: "+e.message);}};
  const addNode=useCallback(t=>{const id=`n${nid.current++}`;setNodes(p=>[...p,{id,type:t,label:ALL[t].name,x:400+(Math.random()-.5)*200-pan.x/zoom,y:300+(Math.random()-.5)*200-pan.y/zoom}]);setHasData(true);setEditMode(true);},[pan,zoom]);
  const addGroup=useCallback(tpl=>{const id=`g${gid.current++}`;setGroups(p=>[...p,{id,type:tpl.type,label:tpl.name,x:250+(Math.random()-.5)*100-pan.x/zoom,y:180+(Math.random()-.5)*100-pan.y/zoom,w:300,h:220,color:tpl.color,border:tpl.border,dash:tpl.dash}]);setHasData(true);setEditMode(true);},[pan,zoom]);
  // Re-layout: reconstruct children from current geometry, re-run autoLayout
  const reLayout = useCallback(() => {
    if (!nodes.length && !groups.length) return;
    // Sort groups by area (smallest first) to detect nesting
    const sortedG = [...groups].sort((a,b)=>(a.w*a.h)-(b.w*b.h));
    const gChildren = {};
    groups.forEach(g => { gChildren[g.id] = []; });
    // Assign each node to the smallest group that contains it
    nodes.forEach(n => {
      for (const g of sortedG) {
        if (n.x >= g.x && n.x <= g.x+g.w && n.y >= g.y && n.y <= g.y+g.h) {
          gChildren[g.id].push(n.id); break;
        }
      }
    });
    // Assign each group to the smallest parent group that contains it
    sortedG.forEach(cg => {
      for (const pg of sortedG) {
        if (pg.id !== cg.id && cg.x >= pg.x && cg.y >= pg.y && cg.x+cg.w <= pg.x+pg.w && cg.y+cg.h <= pg.y+pg.h) {
          // pg contains cg — but only add if pg is bigger
          if (pg.w*pg.h > cg.w*cg.h) { gChildren[pg.id].push(cg.id); break; }
        }
      }
    });
    const rebuilt = {
      title, groups: groups.map(g => ({id:g.id, type:g.type, label:g.label, children:gChildren[g.id]})),
      nodes: nodes.map(n => ({id:n.id, type:n.type, label:n.label})),
      edges: edges.map(e => ({from:e.from, to:e.to, label:e.label, style:e.style})),
    };
    const r = autoLayout(rebuilt);
    setTitle(r.title); setNodes(r.nodes); setGroups(r.groups); setEdges(r.edges);
    setSel(null); setTimeout(() => zoomToFit(r.nodes, r.groups), 100);
  }, [nodes, groups, edges, title, zoomToFit]);

  const handleExport=()=>{const svg=mainRef.current?.querySelector("svg");if(!svg)return;const c=svg.cloneNode(true);c.setAttribute("xmlns","http://www.w3.org/2000/svg");const b=new Blob([new XMLSerializer().serializeToString(c)],{type:"image/svg+xml"});const u=URL.createObjectURL(b);const a=document.createElement("a");a.href=u;a.download=`azure-${Date.now()}.svg`;a.click();URL.revokeObjectURL(u);};

  const toSvg=useCallback((cx,cy)=>{if(!svgRef.current)return{x:0,y:0};const r=svgRef.current.getBoundingClientRect();return{x:(cx-r.left-pan.x)/zoom,y:(cy-r.top-pan.y)/zoom};},[pan,zoom]);
  const px=e=>e.clientX??e.touches?.[0]?.clientX??0;const py=e=>e.clientY??e.touches?.[0]?.clientY??0;
  const onNodeDown=(e,id)=>{if(!editMode)return;e.stopPropagation();if(connectFrom){if(connectFrom!==id)setEdges(p=>[...p,{id:`e${Date.now()}`,from:connectFrom,to:id,label:edgeLbl,style:edgeStyle}]);setEdgeLbl("");setConnectFrom(null);return;}const pt=toSvg(px(e),py(e));const nd=nodes.find(n=>n.id===id);setDrag({kind:"node",id,ox:pt.x-nd.x,oy:pt.y-nd.y});setSel({kind:"node",id});};
  const onGroupDown=(e,id)=>{if(!editMode)return;e.stopPropagation();if(connectFrom){if(connectFrom!==id)setEdges(p=>[...p,{id:`e${Date.now()}`,from:connectFrom,to:id,label:edgeLbl,style:edgeStyle}]);setEdgeLbl("");setConnectFrom(null);return;}const pt=toSvg(px(e),py(e));const g=groups.find(g=>g.id===id);setDrag({kind:"group",id,ox:pt.x-g.x,oy:pt.y-g.y,lastX:pt.x,lastY:pt.y});setSel({kind:"group",id});};
  const onResizeDown=(e,id)=>{if(!editMode)return;e.stopPropagation();const g=groups.find(g=>g.id===id);setRsz({id,sw:g.w,sh:g.h,sx:px(e),sy:py(e)});};
  const onMove=useCallback(e=>{const x=px(e),y=py(e);if(drag){e.preventDefault?.();const pt=toSvg(x,y);if(drag.kind==="node")setNodes(p=>p.map(n=>n.id===drag.id?{...n,x:pt.x-drag.ox,y:pt.y-drag.oy}:n));else{
    const dx=pt.x-drag.lastX,dy=pt.y-drag.lastY;
    drag.lastX=pt.x;drag.lastY=pt.y;
    // Find all child groups recursively that are geometrically inside
    const g=groups.find(g=>g.id===drag.id);
    if(g){
      const childGids=new Set();
      const findChildren=(pg)=>{
        groups.forEach(cg=>{
          if(cg.id!==pg.id&&!childGids.has(cg.id)&&cg.x>=pg.x&&cg.y>=pg.y&&cg.x+cg.w<=pg.x+pg.w&&cg.y+cg.h<=pg.y+pg.h){
            childGids.add(cg.id);findChildren(cg);
          }
        });
      };
      findChildren(g);
      // Move this group + all child groups
      setGroups(p=>p.map(gr=>(gr.id===drag.id||childGids.has(gr.id))?{...gr,x:gr.x+dx,y:gr.y+dy}:gr));
      // Move all nodes inside this group or any child group
      setNodes(p=>p.map(n=>{
        if(n.x>=g.x&&n.x<=g.x+g.w&&n.y>=g.y&&n.y<=g.y+g.h) return {...n,x:n.x+dx,y:n.y+dy};
        return n;
      }));
    }
  }}else if(rsz){e.preventDefault?.();setGroups(p=>p.map(g=>g.id===rsz.id?{...g,w:Math.max(160,rsz.sw+(x-rsz.sx)/zoom),h:Math.max(100,rsz.sh+(y-rsz.sy)/zoom)}:g));}else if(panSt){setPan({x:x-panSt.sx,y:y-panSt.sy});}},[drag,rsz,panSt,toSvg,zoom,groups]);
  const onUp=useCallback(()=>{setDrag(null);setRsz(null);setPanSt(null);},[]);
  const onCanvasDown=e=>{if(e.target===svgRef.current||e.target.closest(".cbg")){setSel(null);setConnectFrom(null);setPanSt({sx:px(e)-pan.x,sy:py(e)-pan.y});}};
  useEffect(()=>{const o={passive:false};window.addEventListener("mousemove",onMove);window.addEventListener("mouseup",onUp);window.addEventListener("touchmove",onMove,o);window.addEventListener("touchend",onUp);return ()=>{window.removeEventListener("mousemove",onMove);window.removeEventListener("mouseup",onUp);window.removeEventListener("touchmove",onMove);window.removeEventListener("touchend",onUp);};},[onMove,onUp]);
  const onWheel=e=>{e.preventDefault();setZoom(z=>Math.max(.1,Math.min(5,z*(e.deltaY>0?.92:1.08))));};
  const delSel=()=>{if(!sel)return;if(sel.kind==="node"){setNodes(p=>p.filter(n=>n.id!==sel.id));setEdges(p=>p.filter(e=>e.from!==sel.id&&e.to!==sel.id));}else if(sel.kind==="group")setGroups(p=>p.filter(g=>g.id!==sel.id));else if(sel.kind==="edge")setEdges(p=>p.filter(e=>e.id!==sel.id));setSel(null);};
  const rename=(id,k,l)=>{if(k==="node")setNodes(p=>p.map(n=>n.id===id?{...n,label:l}:n));else setGroups(p=>p.map(g=>g.id===id?{...g,label:l}:g));};
  const selNode=sel?.kind==="node"?nodes.find(n=>n.id===sel.id):null;
  const selGroup=sel?.kind==="group"?groups.find(g=>g.id===sel.id):null;
  const selEdge=sel?.kind==="edge"?edges.find(e=>e.id===sel.id):null;

  return (
    <div style={{minHeight:"100vh",background:T.bg,color:T.text,fontFamily:"'Segoe UI',system-ui,sans-serif"}}>
      <header style={{padding:"8px 16px",borderBottom:`1px solid ${T.bdr}`,display:"flex",alignItems:"center",justifyContent:"space-between",background:T.hbg}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          {isMobile&&<button onClick={()=>setDrawerOpen(v=>!v)} style={{padding:8,background:"transparent",border:"none",color:T.text,fontSize:18,cursor:"pointer"}}>☰</button>}
          <div style={{width:26,height:26,borderRadius:5,background:"linear-gradient(135deg,#0078D4,#5C2D91)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:"white"}}>◈</div>
          <h1 style={{margin:0,fontSize:13,fontWeight:700}}>Azure Diagram</h1>
        </div>
        <div style={{display:"flex",gap:5}}>
          {hasData&&<button onClick={()=>setEditMode(v=>!v)} style={{padding:"5px 12px",background:editMode?"rgba(59,130,246,.12)":"transparent",border:`1px solid ${editMode?T.sel:T.bdr}`,borderRadius:5,color:editMode?T.sel:T.ts,fontSize:10,cursor:"pointer",fontWeight:editMode?600:400}}>{editMode?"✓ Editing":"✎ Edit"}</button>}
          <button onClick={()=>setTheme(t=>t==="dark"?"light":"dark")} style={{padding:"5px 10px",background:"transparent",border:`1px solid ${T.bdr}`,borderRadius:5,color:T.ts,fontSize:10,cursor:"pointer"}}>{theme==="dark"?"☀":"●"}</button>
          {hasData&&<button onClick={reLayout} style={{padding:"5px 10px",background:"transparent",border:`1px solid ${T.bdr}`,borderRadius:5,color:T.ts,fontSize:10,cursor:"pointer"}}>⟲ Layout</button>}
          {hasData&&<button onClick={()=>zoomToFit(nodes,groups)} style={{padding:"5px 10px",background:"transparent",border:`1px solid ${T.bdr}`,borderRadius:5,color:T.ts,fontSize:10,cursor:"pointer"}}>⊙ Fit</button>}
          {hasData&&<button onClick={handleExport} style={{padding:"5px 10px",background:"transparent",border:`1px solid ${T.bdr}`,borderRadius:5,color:T.ts,fontSize:10,cursor:"pointer"}}>↓ SVG</button>}
        </div>
      </header>
      <div style={{display:"flex",minHeight:"calc(100vh - 45px)"}}>
        {isMobile&&drawerOpen&&<div onClick={()=>setDrawerOpen(false)} style={{position:"fixed",inset:0,top:45,background:"rgba(0,0,0,.5)",zIndex:40}}/>}
        <aside style={{width:isMobile?"85vw":280,position:isMobile?"fixed":"relative",left:isMobile?(drawerOpen?0:"-100%"):0,top:isMobile?45:0,height:isMobile?"calc(100vh-45px)":"auto",zIndex:isMobile?50:1,transition:"left .3s",borderRight:`1px solid ${T.bdr}`,padding:10,display:"flex",flexDirection:"column",gap:7,overflowY:"auto",flexShrink:0,background:T.srf}}>
          <div><label style={lbl(T)}>EXAMPLES</label><div style={{display:"flex",gap:3,flexWrap:"wrap"}}>{[["threetier","3-Tier Web"],["iot","IoT Pipeline"],["hybrid","Hybrid Cloud"]].map(([k,l])=> <button key={k} onClick={()=>setActiveEx(k)} style={{padding:"4px 8px",borderRadius:4,border:`1px solid ${activeEx===k?"#0078D4":T.bdr}`,background:activeEx===k?"rgba(0,120,212,.1)":"transparent",color:activeEx===k?"#0078D4":T.ts,fontSize:9,cursor:"pointer"}}>{l}</button>)}</div></div>
          {activeEx&&<button onClick={()=>loadDemo(activeEx)} style={{padding:9,borderRadius:5,border:"none",background:"linear-gradient(135deg,#0078D4,#5C2D91)",color:"white",fontSize:11,fontWeight:600,cursor:"pointer"}}>▶ Load Demo</button>}
          <div><label style={lbl(T)}>DESCRIBE OR PASTE JSON</label><textarea value={input} onChange={e=>setInput(e.target.value)} placeholder={"Describe your architecture...\nor paste diagram JSON"} style={{width:"100%",minHeight:90,padding:8,borderRadius:4,border:`1px solid ${T.bdr}`,background:T.bg,color:T.text,fontSize:10,fontFamily:"Consolas,monospace",lineHeight:1.5,resize:"vertical",outline:"none",boxSizing:"border-box"}}/>
            <div style={{display:"flex",gap:4,marginTop:4}}>
              <button onClick={generate} disabled={loading||!input.trim()} style={{flex:1,padding:7,borderRadius:5,border:"none",background:loading?T.bdr:"linear-gradient(135deg,#0078D4,#5C2D91)",color:"white",fontSize:10,fontWeight:600,cursor:loading?"wait":"pointer",opacity:!input.trim()?.4:1}}>{loading?"⟳ Generating…":"⚡ Generate"}</button>
              <button onClick={loadJson} disabled={!input.trim()} style={{flex:1,padding:7,borderRadius:5,border:`1px solid ${T.bdr}`,background:"transparent",color:T.ts,fontSize:10,cursor:"pointer",opacity:!input.trim()?.4:1}}>📋 Load JSON</button>
            </div>
            {genError&&<div style={{marginTop:4,padding:"5px 8px",borderRadius:4,background:"rgba(239,68,68,.08)",border:"1px solid rgba(239,68,68,.2)",color:"#F87171",fontSize:8,userSelect:"text",wordBreak:"break-all",maxHeight:60,overflowY:"auto"}}>{genError}</div>}
          </div>
          {editMode&&hasData&&<div style={{padding:8,borderRadius:4,border:`1px solid ${T.sel}40`,background:theme==="dark"?"rgba(59,130,246,.04)":"rgba(59,130,246,.03)"}}><p style={{margin:0,fontSize:8,color:T.ts,lineHeight:1.5}}><b style={{color:T.sel}}>Edit</b> — Drag · Click node → Connect/Delete · Resize groups via corner handle</p></div>}
          <div style={{borderRadius:5,border:`1px solid ${T.bdr}`,overflow:"hidden",marginTop:"auto"}}><button onClick={()=>setShowPalette(v=>!v)} style={{width:"100%",padding:"6px 10px",background:"transparent",border:"none",color:T.ts,fontSize:9,cursor:"pointer",textAlign:"left",display:"flex",justifyContent:"space-between"}}><span>Manual Palette</span><span>{showPalette?"▾":"▸"}</span></button>
            {showPalette&&<div style={{padding:"4px 8px 8px",borderTop:`1px solid ${T.bdr}`,background:T.bg,maxHeight:240,overflowY:"auto"}}>
              <label style={{...lbl(T),marginTop:2}}>GROUPS</label><div style={{display:"flex",gap:3,flexWrap:"wrap",marginBottom:6}}>{GTS.map(t=> <button key={t.type} onClick={()=>addGroup(t)} style={{padding:"3px 6px",borderRadius:4,border:`1px solid ${t.border}30`,background:"transparent",color:T.ts,fontSize:8,cursor:"pointer"}}>{t.name}</button>)}</div>
              {Object.entries(CATS).map(([k,cat])=> <div key={k}><button onClick={()=>setOpenCat(openCat===k?null:k)} style={{width:"100%",display:"flex",alignItems:"center",gap:5,padding:"3px 0",background:"transparent",border:"none",color:openCat===k?cat.color:T.tm,cursor:"pointer",fontSize:10,fontWeight:600,textAlign:"left"}}><span style={{width:5,height:5,borderRadius:"50%",background:cat.color,opacity:openCat===k?1:.35}}/>{cat.label}</button>
                {openCat===k&&<div style={{display:"flex",gap:3,flexWrap:"wrap",marginBottom:4,paddingLeft:10}}>{cat.items.map(item=> <button key={item.type} onClick={()=>addNode(item.type)} style={{display:"flex",alignItems:"center",gap:3,padding:"2px 5px",borderRadius:3,border:`1px solid ${T.bdr}`,background:"transparent",color:T.ts,fontSize:8,cursor:"pointer"}}><img src={ICONS[item.type]} width={12} height={12} alt=""/>{item.name}</button>)}</div>}</div>)}</div>}</div>
        </aside>
        <main ref={mainRef} style={{flex:1,position:"relative",overflow:"hidden"}}>
          {!hasData&&<div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",textAlign:"center",opacity:.5,pointerEvents:"none"}}><div style={{fontSize:40,marginBottom:10,opacity:.3}}>☁</div><p style={{fontSize:13,fontWeight:600,color:T.ts,margin:"0 0 6px"}}>Azure Deployment Diagram</p><p style={{fontSize:10,color:T.tm,lineHeight:1.6}}>Pick an example → Load<br/>Or describe to Claude, paste JSON, click Load</p></div>}
          {hasData&&<svg ref={svgRef} width="100%" height="100%" onMouseDown={onCanvasDown} onTouchStart={onCanvasDown} onWheel={onWheel} style={{cursor:panSt?"grabbing":"default",touchAction:"none",position:"absolute",inset:0}}>
            <defs><marker id="ah" markerWidth="8" markerHeight="6" refX="7" refY="3" orient="auto"><polygon points="0 0,8 3,0 6" fill={T.tm}/></marker><marker id="ahS" markerWidth="8" markerHeight="6" refX="7" refY="3" orient="auto"><polygon points="0 0,8 3,0 6" fill={T.sel}/></marker><pattern id="grd" width="20" height="20" patternUnits="userSpaceOnUse"><circle cx="10" cy="10" r=".4" fill={theme==="dark"?"#1a2036":"#dde4ed"}/></pattern></defs>
            <g className="cbg"><rect width="100%" height="100%" fill={T.bg}/>{grid&&<rect width="100%" height="100%" fill="url(#grd)"/>}</g>
            <g transform={`translate(${pan.x},${pan.y}) scale(${zoom})`}>
              {groups.map(g=>{const isSel=sel?.kind==="group"&&sel.id===g.id;const d=g.depth||0;const bw=isSel?2.5:Math.max(1,2-d*0.4);const fillOp=Math.max(4,10-d*2).toString(16).padStart(2,'0'); return (
                <g key={g.id}><rect x={g.x} y={g.y} width={g.w} height={g.h} rx={Math.max(6,10-d*2)} fill={g.color+fillOp} stroke={isSel?T.sel:g.border+(d>0?"40":"60")} strokeWidth={bw} strokeDasharray={g.dash?"8 4":"none"} style={{cursor:editMode?(connectFrom?"crosshair":"grab"):"default"}} onMouseDown={e=>onGroupDown(e,g.id)} onTouchStart={e=>onGroupDown(e,g.id)}/><rect x={g.x} y={g.y} width={g.w} height={d>0?24:28} rx={Math.max(6,10-d*2)} fill={g.color+(d>0?"0c":"14")} style={{pointerEvents:"none"}}/><rect x={g.x} y={g.y+(d>0?16:20)} width={g.w} height={8} fill={g.color+(d>0?"0c":"14")} style={{pointerEvents:"none"}}/><text x={g.x+(d>0?8:12)} y={g.y+(d>0?16:18)} fill={g.border} fontSize={d>0?10:11} fontWeight="600" fontFamily="Segoe UI" style={{pointerEvents:"none"}}>{g.label}</text>{editMode&&<><rect x={g.x+g.w-16} y={g.y+g.h-16} width={16} height={16} rx={4} fill="transparent" style={{cursor:"nwse-resize"}} onMouseDown={e=>onResizeDown(e,g.id)} onTouchStart={e=>onResizeDown(e,g.id)}/><path d={`M${g.x+g.w-5} ${g.y+g.h-12}L${g.x+g.w-5} ${g.y+g.h-5}L${g.x+g.w-12} ${g.y+g.h-5}`} fill="none" stroke={g.border+"40"} strokeWidth="1.5" style={{pointerEvents:"none"}}/></>}</g>
              );})}
              {edges.map(edge=>{
                // Resolve endpoint from nodes or groups
                const resolvePoint = (id) => {
                  const nd = nodes.find(n=>n.id===id);
                  if (nd) return {x:nd.x, y:nd.y, r:30};
                  const g = groups.find(g=>g.id===id);
                  if (g) return {x:g.x+g.w/2, y:g.y+g.h/2, r:Math.min(g.w,g.h)/2};
                  return null;
                };
                const a=resolvePoint(edge.from), b=resolvePoint(edge.to);
                if(!a||!b)return null;const p=edgePath(a,b);const isSel=sel?.kind==="edge"&&sel.id===edge.id; return (
                <g key={edge.id} style={{cursor:"pointer"}} onClick={e=>{e.stopPropagation();setSel({kind:"edge",id:edge.id});}}><path d={p} fill="none" stroke="transparent" strokeWidth="14"/><path d={p} fill="none" stroke={isSel?T.sel:T.tm} strokeWidth={isSel?2.5:1.3} strokeDasharray={edge.style==="dashed"?"6 3":"none"} markerEnd={isSel?"url(#ahS)":"url(#ah)"} opacity={isSel?1:.45}/>{edge.label&&(()=>{const mx=(a.x+b.x)/2,my=(a.y+b.y)/2-10; return <g><rect x={mx-edge.label.length*3.2-5} y={my-9} width={edge.label.length*6.4+10} height={14} rx={7} fill={T.srf} stroke={T.bdr} strokeWidth=".5"/><text x={mx} y={my} textAnchor="middle" fill={isSel?T.sel:T.ts} fontSize="8.5" fontFamily="Consolas,monospace" fontWeight="500">{edge.label}</text></g>;})()}</g>
              );})}
              {nodes.map(nd=>{const s=ALL[nd.type];if(!s)return null;const isSel=sel?.kind==="node"&&sel.id===nd.id;const isCon=connectFrom===nd.id; return (
                <g key={nd.id} onMouseDown={e=>onNodeDown(e,nd.id)} onTouchStart={e=>onNodeDown(e,nd.id)} style={{cursor:editMode?(connectFrom?"crosshair":"grab"):"default"}}>{(isSel||isCon)&&<rect x={nd.x-32} y={nd.y-32} width={64} height={64} rx={14} fill="none" stroke={isCon?"#f59e0b":T.sel} strokeWidth="2" opacity=".45" strokeDasharray={isCon?"4 2":"none"}/>}<rect x={nd.x-28} y={nd.y-28} width={56} height={56} rx={12} fill={T.nBg} stroke={isSel?T.sel+"80":T.nSt} strokeWidth={isSel?1.5:1}/><image href={ICONS[nd.type]} x={nd.x-14} y={nd.y-14} width={28} height={28} style={{pointerEvents:"none"}}/><text x={nd.x} y={nd.y+40} textAnchor="middle" fill={T.ts} fontSize="9" fontFamily="Segoe UI" fontWeight="500" style={{pointerEvents:"none"}}>{nd.label.length>16?nd.label.slice(0,15)+"…":nd.label}</text></g>
              );})}
            </g>
            <text x="50%" y="24" textAnchor="middle" fill={T.tf} fontSize="14" fontWeight="600" fontFamily="Segoe UI" letterSpacing=".06em">{title}</text>
          </svg>}
          {connectFrom&&<div style={{position:"absolute",top:8,left:"50%",transform:"translateX(-50%)",fontSize:11,color:"#fbbf24",padding:"4px 14px",background:"rgba(245,158,11,.08)",border:"1px solid rgba(245,158,11,.18)",borderRadius:7}}>Click target node or group</div>}
          {editMode&&(selNode||selGroup||selEdge)&&<div style={{position:"absolute",top:8,right:10,width:195,background:T.hbg,border:`1px solid ${T.bdr}`,borderRadius:10,padding:11,boxShadow:"0 8px 32px rgba(0,0,0,.3)",backdropFilter:"blur(12px)"}}>
            {selNode&&<><div style={{display:"flex",alignItems:"center",gap:7,marginBottom:8}}><img src={ICONS[selNode.type]} width={22} height={22} alt=""/><div style={{fontSize:10,fontWeight:600}}>{ALL[selNode.type].name}</div></div><label style={pl}>Label</label><input value={selNode.label} onChange={e=>rename(sel.id,"node",e.target.value)} style={pi(T)}/><label style={pl}>Edge label</label><input value={edgeLbl} onChange={e=>setEdgeLbl(e.target.value)} placeholder="HTTPS, 443" style={pi(T)}/><label style={pl}>Line</label><div style={{display:"flex",gap:3,marginBottom:4}}>{["solid","dashed"].map(s=> <button key={s} onClick={()=>setEdgeStyle(s)} style={{flex:1,padding:"3px 0",background:edgeStyle===s?"rgba(59,130,246,.1)":"transparent",border:`1px solid ${edgeStyle===s?T.sel+"50":T.bdr}`,borderRadius:4,color:edgeStyle===s?T.sel:T.tm,cursor:"pointer",fontSize:9,fontWeight:600,textTransform:"capitalize"}}>{s}</button>)}</div><div style={{display:"flex",gap:4,marginTop:5}}><button onClick={()=>setConnectFrom(sel.id)} style={{...pa,background:"rgba(59,130,246,.1)",color:"#60a5fa"}}>⟶ Connect</button><button onClick={delSel} style={{...pa,background:"rgba(239,68,68,.08)",color:"#f87171"}}>✕</button></div></>}
            {selGroup&&<><label style={pl}>Label</label><input value={selGroup.label} onChange={e=>rename(sel.id,"group",e.target.value)} style={pi(T)}/><label style={pl}>Edge label</label><input value={edgeLbl} onChange={e=>setEdgeLbl(e.target.value)} placeholder="VNet Peering" style={pi(T)}/><label style={pl}>Line</label><div style={{display:"flex",gap:3,marginBottom:4}}>{["solid","dashed"].map(s=> <button key={s} onClick={()=>setEdgeStyle(s)} style={{flex:1,padding:"3px 0",background:edgeStyle===s?"rgba(59,130,246,.1)":"transparent",border:`1px solid ${edgeStyle===s?T.sel+"50":T.bdr}`,borderRadius:4,color:edgeStyle===s?T.sel:T.tm,cursor:"pointer",fontSize:9,fontWeight:600,textTransform:"capitalize"}}>{s}</button>)}</div><div style={{display:"flex",gap:4,marginTop:5}}><button onClick={()=>setConnectFrom(sel.id)} style={{...pa,background:"rgba(59,130,246,.1)",color:"#60a5fa"}}>⟶ Connect</button><button onClick={delSel} style={{...pa,background:"rgba(239,68,68,.08)",color:"#f87171"}}>✕</button></div></>}
            {selEdge&&<><label style={pl}>Label</label><input value={selEdge.label} onChange={e=>setEdges(p=>p.map(ed=>ed.id===sel.id?{...ed,label:e.target.value}:ed))} style={pi(T)}/><label style={pl}>Style</label><div style={{display:"flex",gap:3}}>{["solid","dashed"].map(s=> <button key={s} onClick={()=>setEdges(p=>p.map(ed=>ed.id===sel.id?{...ed,style:s}:ed))} style={{flex:1,padding:"3px 0",background:selEdge.style===s?"rgba(59,130,246,.1)":"transparent",border:`1px solid ${selEdge.style===s?T.sel+"50":T.bdr}`,borderRadius:4,color:selEdge.style===s?T.sel:T.tm,cursor:"pointer",fontSize:9,fontWeight:600,textTransform:"capitalize"}}>{s}</button>)}</div><button onClick={delSel} style={{...pa,width:"100%",marginTop:5,background:"rgba(239,68,68,.08)",color:"#f87171"}}>✕ Delete</button></>}
          </div>}
          <div style={{position:"absolute",bottom:12,right:12,display:"flex",alignItems:"center",gap:0,background:T.hbg,border:`1px solid ${T.bdr}`,borderRadius:8,overflow:"hidden",boxShadow:"0 2px 8px rgba(0,0,0,.2)",zIndex:20}}>
            <button onClick={()=>setZoom(z=>Math.max(.1,z*.85))} style={{padding:"6px 10px",background:"transparent",border:"none",borderRight:`1px solid ${T.bdr}`,color:T.ts,fontSize:14,cursor:"pointer",lineHeight:1}}>−</button>
            <span style={{padding:"4px 8px",fontSize:10,color:T.tf,minWidth:40,textAlign:"center"}}>{Math.round(zoom*100)}%</span>
            <button onClick={()=>setZoom(z=>Math.min(5,z*1.18))} style={{padding:"6px 10px",background:"transparent",border:"none",borderRight:`1px solid ${T.bdr}`,borderLeft:`1px solid ${T.bdr}`,color:T.ts,fontSize:14,cursor:"pointer",lineHeight:1}}>+</button>
            <button onClick={()=>zoomToFit(nodes,groups)} style={{padding:"6px 10px",background:"transparent",border:"none",color:T.ts,fontSize:12,cursor:"pointer",lineHeight:1}}>⊙</button>
          </div>
        </main>
      </div>
      <style>{`*{box-sizing:border-box;user-select:none}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:${T.bdr};border-radius:3px}textarea::placeholder{color:${T.tf}}textarea,input{user-select:text}`}</style>
    </div>
  );
}
const lbl=T=>({fontSize:8,color:T.tm,fontFamily:"Consolas,monospace",letterSpacing:"1.5px",display:"block",marginBottom:3});
const pl={display:"block",fontSize:8,color:"#64748b",marginBottom:2,marginTop:6,textTransform:"uppercase",letterSpacing:".06em"};
const pi=T=>({width:"100%",padding:"4px 6px",background:T.bg,border:`1px solid ${T.bdr}`,borderRadius:4,color:T.text,fontSize:10,outline:"none",boxSizing:"border-box"});
const pa={flex:1,padding:"5px 0",border:"none",borderRadius:5,cursor:"pointer",fontSize:10,fontWeight:600};
